import React from 'react';
import { history } from 'umi';
import { observer, inject } from 'mobx-react';
import { toJS } from 'mobx';
import { Guide } from 'bizcharts';
import { errBoundary } from '@/components/ErrorBoundary';
import CompoundChart, { IGeom, enum_geom_type } from '@/components/CompoundChart';
import PieChart from '@/components/PieChart';
import { UIStore } from '@/store/UI';
import StatisticsStore, {
    IOperationRateDOD,
    IFactoryData,
    initFactoryData,
    IMaintainData,
    initMaintainData
} from '@/store/Statistics/typings';
import AnalysisStore, {
    enum_date_type,
    IOrderDODItem,
    initOrderDODItem,
    IRevenueDODItem,
    initRevenueDODItem,
    IPositiveRateDODItem,
    IShareRateDODItem,
    IRepurchaseRateDODItem,
    enum_chart_type,
    enum_analysis_factory_type
} from '@/store/Analysis/typings';
import TargetSettingStore, { enum_month_name, enum_target_type } from '@/store/TargetSetting/typing';
import { formatDate, formatPreDay, removeEmpty, getSize, getMonthDays } from '@/utils/method';
import { Layout } from 'antd';
import { CaretUpFilled, CaretDownFilled } from '@ant-design/icons';
import styles from './index.less';

interface IProps {
    analysisStore: AnalysisStore;
    statisticsStore: StatisticsStore;
    uiStore: UIStore;
    targetSettingStore: TargetSettingStore;
}

interface IState {
    factoryData: IFactoryData; // 当前站点数据
    maintainData: IMaintainData; // 当前维护站点数据

    recentOrderDOD: IOrderDODItem[]; // 最近七天订单环比
    monthOrderData: IOrderDODItem; // 本月订单统计
    recentRevenueDOD: IRevenueDODItem[]; // 最近七天营收环比
    monthRevenueData: IRevenueDODItem; // 本月营收统计
    positiveRateDOD: IPositiveRateDODItem[]; // 近30日好评率
    shareRateDOD: IShareRateDODItem[]; // 近30日分享率
    repurchaseRateDOD: IRepurchaseRateDODItem[]; // 近30日复购率
    operationRateDOD: IOperationRateDOD[]; // 近30日运营率
    monthProfitTarget: number; // 本月目标毛利，平均到每天 * 本月已过天数
}

const { Content, Header } = Layout;

@inject('analysisStore', 'statisticsStore', 'uiStore', 'targetSettingStore')
@observer
class Index extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            factoryData: initFactoryData,
            maintainData: initMaintainData,

            recentOrderDOD: [],
            monthOrderData: initOrderDODItem,
            recentRevenueDOD: [],
            monthRevenueData: initRevenueDODItem,
            positiveRateDOD: [],
            shareRateDOD: [],
            repurchaseRateDOD: [],
            operationRateDOD: [],
            monthProfitTarget: 0
        };
    }
    componentDidMount() {
        const _this = this;
        _this.initData();
    }
    componentWillUnmount() {
        window.onresize = null;
    }
    initData = async () => {
        const { analysisStore, statisticsStore, uiStore, targetSettingStore } = this.props;
        const {
            getOrderCountAnalysis,
            getRevenueAnalysis,
            getPositiveRateAnalysis,
            getShareRateAnalysis,
            getRepurchaseRateAnalysis
        } = analysisStore;
        const { getOperationRateDOD, getFactoryData, getMaintainData } = statisticsStore;
        const { getTargetData } = targetSettingStore;
        uiStore.openLoading();
        // 计算需要用到的时间节点
        const now = new Date();
        const day7DateStr = formatPreDay(now, 7); // 计算7天前的日期
        const day30DateStr = formatPreDay(now, 30); // 计算30天前的日期
        const nowStr = formatDate(now, 'YYYY-MM-DD');
        const nowMonth = formatDate(now, 'YYYY-MM-01'); // 通过获取 年月 + '-01' 来得到本月第一天的日期
        const endYear = formatDate(now, 'YYYY');
        const endMonth = enum_month_name['M' + formatDate(now, 'MM')];
        const result = await Promise.all([
            getFactoryData(), // 0 获取站点统计数据
            getMaintainData(), // 1 获取维修统计数据

            getOrderCountAnalysis({ startTime: day7DateStr, endTime: nowStr, type: enum_date_type.day }), // 2 获取最近七日订单环比
            getOrderCountAnalysis({ startTime: nowMonth, endTime: nowStr, type: enum_date_type.month }), // 3 获取本月单量统计
            getRevenueAnalysis({
                startTime: day7DateStr,
                endTime: nowStr,
                type: enum_date_type.day,
                f_skill_score: enum_analysis_factory_type.self
            }), // 4 获取最近七日营收环比
            getRevenueAnalysis({
                startTime: nowMonth,
                endTime: nowStr,
                type: enum_date_type.month,
                f_skill_score: enum_analysis_factory_type.self
            }), // 5 获取本月营收统计
            getPositiveRateAnalysis({ startTime: day30DateStr, endTime: nowStr, orderType: '0' }), // 6 获取30日好评率环比
            getShareRateAnalysis({ startTime: day30DateStr, endTime: nowStr, type: 1 }), // 7 获取30日转介绍率环比
            getRepurchaseRateAnalysis({ startTime: day30DateStr, endTime: nowStr, type: 1 }), // 8 获取30日复购率环比
            getOperationRateDOD(day30DateStr, nowStr), // 9 获取30日运营率环比
            getTargetData({
                f_year: endYear,
                f_month: endMonth,
                f_type: enum_target_type.profit
            }) // 10 获取本月营收目标
        ]);
        const { data: factoryData } = result[0];
        const { data: maintainData } = result[1];
        const { data: recentOrderDOD } = result[2];
        const { data: monthOrderData } = result[3];
        const { data: recentRevenueDOD } = result[4];
        const { data: monthRevenueData } = result[5];
        const { data: positiveRateDOD } = result[6];
        const { data: shareRateDOD } = result[7];
        const { data: repurchaseRateDOD } = result[8];
        const { data: operationRateDOD } = result[9];
        const { data: monthProfitTarget } = result[10];

        const dayProfitTarget =
            Object.values((monthProfitTarget && monthProfitTarget[0]) || {})[0] || 0 / getMonthDays(now); // 当月 天毛利目标
        this.setState(
            removeEmpty({
                factoryData,
                maintainData,

                recentOrderDOD,
                monthOrderData: monthOrderData && monthOrderData[0],
                recentRevenueDOD,
                monthRevenueData: monthRevenueData && monthRevenueData[0],
                positiveRateDOD,
                shareRateDOD,
                repurchaseRateDOD,
                operationRateDOD,
                monthProfitTarget: dayProfitTarget * new Date().getDate()
            })
        );
        uiStore.closeLoading();
    };
    goToPage = (type: enum_chart_type) => () => {
        this.props.analysisStore.changeChartType(type);
        history.push('/analysis');
    };
    goToKanBan = () => {
        window.location.href = `${APP_CONFIG.MAPIC_CDN}kanban/index.html`;
    };

    render() {
        const _this = this;
        const {
            factoryData,
            maintainData,

            recentOrderDOD,
            monthOrderData,
            recentRevenueDOD,
            monthRevenueData,
            positiveRateDOD,
            shareRateDOD,
            repurchaseRateDOD,
            operationRateDOD,
            monthProfitTarget
        } = _this.state;
        const { uiStore } = _this.props;
        const computedProfitCompleteRate = () => {
            if (monthProfitTarget < 0) {
                return ((2 - monthRevenueData?.grossProfit / monthProfitTarget || 0) * 100).toFixed(2);
            } else if (monthProfitTarget > 0) {
                return ((monthRevenueData?.grossProfit / monthProfitTarget || 0) * 100).toFixed(2);
            } else {
                return '--';
            }
        };
        const getGuideMarker = (data, xKeyName, yKeyName) => () => {
            if (data.length > 0) {
                // 只显示
                const newData = toJS(data);
                const length = newData.length;
                const position = [newData[length - 1][xKeyName], newData[length - 1][yKeyName]];
                return position; //位置信息
            }
        };
        // 配置折线的config
        const getLineConfig = (typeKey: string, typeName: string) => ({
            type: enum_geom_type.LINE,
            size: getSize(3),
            configList: [
                {
                    typeKey,
                    typeName,
                    color: '#f3a536'
                }
            ]
        });
        const getChartChildren = (data, xKeyName, yKeyName) => {
            return (
                <React.Fragment>
                    {data.length > 0 && (
                        <Guide>
                            <Guide.Region
                                start={['90%', '-20%']} // 辅助框起始位置，值为原始数据值，支持 callback
                                end={['110%', '120%']} // 辅助框结束位置，值为原始数据值，支持 callback
                                style={{
                                    lineWidth: 0, // 辅助框的边框宽度
                                    fill: '#eee', // 辅助框填充的颜色
                                    fillOpacity: 1 // 辅助框的背景透明度
                                }} // 辅助框的图形样式属性
                            />
                            <Guide.DataMarker
                                top // 指定 giude 是否绘制在 canvas 最上层，默认为 false, 即绘制在最下层
                                position={getGuideMarker(data, xKeyName, yKeyName)}
                                display={{
                                    point: true,
                                    line: false,
                                    text: false
                                }} //可选，是否显示文本/point/line，默认为全部显示
                                style={{
                                    point: {
                                        fill: '#f3a536',
                                        stroke: '#f3a536'
                                    }
                                }}
                            />
                        </Guide>
                    )}
                </React.Fragment>
            );
        };
        // 遍历生成 运营数据 图表
        const operationChartList = [
            {
                title: '今日单量',
                value: recentOrderDOD?.slice(-1)[0]?.num || 0,
                titleTip: `自营单量：${recentOrderDOD?.slice(-1)[0]?.zy || 0}`,
                leftFooter: `当月单量：${monthOrderData?.num}`,
                rightFooter: `成交率：${monthOrderData?.successRate || '0.00'}%`,
                xKeyName: 'day',
                yKeyName: 'num',
                data: recentOrderDOD,
                geomList: [getLineConfig('num', '单量')],
                chartChildren: getChartChildren(recentOrderDOD, 'day', 'num'),
                ifCanClick: true,
                onClick: _this.goToPage(enum_chart_type.orderCount)
            },
            {
                title: '今日营业额',
                value: recentRevenueDOD?.slice(-1)[0]?.revenue || '0.00',
                leftFooter: `当月营业额：${monthRevenueData?.revenue || '0.00'}`,
                rightFooter: `当月客单：${(monthRevenueData?.revenue / monthOrderData?.num || 0).toFixed(2)}`,
                xKeyName: 'day',
                yKeyName: 'income',
                data: recentOrderDOD,
                geomList: [getLineConfig('income', '营业额')],
                chartChildren: getChartChildren(recentOrderDOD, 'day', 'income'),
                ifCanClick: true,
                onClick: _this.goToPage(enum_chart_type.revenue)
            },
            {
                title: '今日毛利',
                value: recentRevenueDOD?.slice(-1)[0]?.grossProfit || '0.00',
                leftFooter: `当月毛利：${monthRevenueData?.grossProfit || '0.00'}`,
                rightFooter: `完成率：${computedProfitCompleteRate()}%`,
                xKeyName: 'f_indate',
                yKeyName: 'grossProfit',
                data: recentRevenueDOD,
                geomList: [getLineConfig('grossProfit', '毛利')],
                chartChildren: getChartChildren(recentRevenueDOD, 'f_indate', 'grossProfit'),
                ifCanClick: true,
                onClick: _this.goToPage(enum_chart_type.revenue)
            }
        ];
        // 遍历生成 反馈数据 图表
        const getPositiveData = () => {
            const newData = {};
            positiveRateDOD.forEach((item: IPositiveRateDODItem) => {
                if (newData[item.f_indate]) {
                    newData[item.f_indate].push(+item.positiveRate);
                } else {
                    newData[item.f_indate] = [+item.positiveRate];
                }
            });
            const data = Object.keys(newData).map(keyItem => ({
                f_indate: keyItem,
                positiveRate: +(
                    newData[keyItem].reduce((preTotal, curData) => preTotal + curData, 0) / newData[keyItem].length
                ).toFixed(2)
            }));
            return data;
        };
        const positiveData = getPositiveData();
        const feedbackChartList = [
            {
                title: '近30日好评率(%)',
                value: (
                    positiveData.reduce((preTotal, item) => preTotal + item?.positiveRate, 0) / positiveData.length || 0
                ).toFixed(2),
                xKeyName: 'f_indate',
                yKeyName: 'positiveRate',
                data: positiveData,
                geomList: [getLineConfig('positiveRate', '好评率')],
                chartChildren: getChartChildren(positiveData, 'f_indate', 'positiveRate'),
                ifCanClick: true,
                onClick: _this.goToPage(enum_chart_type.positiveRate)
            },
            {
                title: '近30日分享率(%)',
                value: (
                    shareRateDOD.reduce((preTotal, item) => preTotal + item?.share_rate, 0) / shareRateDOD.length || 0
                ).toFixed(2),
                xKeyName: 'f_indate',
                yKeyName: 'share_rate',
                data: shareRateDOD,
                geomList: [getLineConfig('share_rate', '分享率')],
                chartChildren: getChartChildren(shareRateDOD, 'f_indate', 'share_rate'),
                ifCanClick: true,
                onClick: _this.goToPage(enum_chart_type.shareRate)
            },
            {
                title: '近30日复购率(%)',
                value: (
                    repurchaseRateDOD.reduce((preTotal, item) => preTotal + item?.repurchaseRate, 0) /
                        repurchaseRateDOD.length || 0
                ).toFixed(2),
                xKeyName: 'f_indate',
                yKeyName: 'repurchaseRate',
                data: repurchaseRateDOD,
                geomList: [getLineConfig('repurchaseRate', '复购率')],
                chartChildren: getChartChildren(repurchaseRateDOD, 'f_indate', 'repurchaseRate'),
                ifCanClick: true,
                onClick: _this.goToPage(enum_chart_type.repurchaseRate)
            }
        ];
        const getIcon = item => {
            const yesterday = +item.data.slice(-2, -1)[0][item.yKeyName];
            const today = +item.data.slice(-1)[0][item.yKeyName];
            return today - yesterday > 0 ? (
                <CaretUpFilled className={styles.caretUp} />
            ) : (
                <CaretDownFilled className={styles.caretDown} />
            );
        };
        const chartProps = item => ({
            padding: ['10%'],
            xConfig: { name: item.xKeyName, visible: false },
            yConfig: { name: item.yKeyName, visible: false },
            ifCanClick: item.ifCanClick,
            data: item.data,
            geomList: item.geomList,
            chartChildren: item.chartChildren
        });
        return (
            <div id="page-homepage">
                <Header className={styles.navHeader}>
                    <div className={styles.headerTitle}>{uiStore.navTitle}</div>
                    <div className={styles.headerRight} onClick={this.goToKanBan} style={{ cursor: 'pointer' }}>
                        地图
                    </div>
                </Header>
                <Content id="page-homepage" className={styles.container}>
                    <div className={styles.leftContainer}>
                        {/* 今日运营数据 */}
                        <div className={styles.operationCard}>
                            {operationChartList.map((item, index) => (
                                <div key={index} className={styles.chartCard} onClick={item.onClick}>
                                    <div className={styles.chartHeader}>
                                        <div className={styles.chartHeaderLeft}>
                                            <div className={styles.chartHeaderTitle}>{item.title}</div>
                                            <div className={styles.chartHeaderVal}>{item.value}</div>
                                        </div>
                                        <div className={styles.chartHeaderRight}>
                                            <div className={styles.chartHeaderTitle}>{item.titleTip}</div>
                                        </div>
                                    </div>
                                    <div id="page-homepage-operationChart" style={{ flex: 1 }}>
                                        <CompoundChart {...chartProps(item)} />
                                    </div>
                                    <div className={styles.chartFooter}>
                                        {item.leftFooter && <div>{item.leftFooter}</div>}
                                        {item.rightFooter && <div>{item.rightFooter}</div>}
                                    </div>
                                </div>
                            ))}
                        </div>
                        {/* 今日反馈数据 */}
                        <div className={styles.feedbackCard}>
                            {feedbackChartList.map((item, index) => (
                                <div key={index} className={styles.chartCard} onClick={item.onClick}>
                                    <div className={styles.chartHeader}>
                                        <div className={styles.headerTip}>
                                            <div className={styles.chartHeaderTitle}>{item.title}</div>
                                            <div className={styles.chartHeaderVal}>
                                                {item.value}
                                                {item.data.length > 1 && getIcon(item)}
                                            </div>
                                        </div>
                                    </div>
                                    <div id="page-homepage-feedbackChart" style={{ flex: 1 }}>
                                        <CompoundChart {...chartProps(item)} />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                    <div className={styles.rightContainer}>
                        {/* 站点统计 */}
                        <div className={styles.factoryCard}>
                            <div className={styles.factoryCardTitle}>运营站点</div>
                            <div className={styles.header}>
                                <div className={styles.headerLeft}>
                                    <div className={styles.headerTitle}>站点总数</div>
                                    <div className={styles.headerVal}>{factoryData.f_factory_total}</div>
                                </div>
                                <div className={styles.headerRight}>
                                    <div className={styles.headerRightLeft}>
                                        <div className={styles.headerTitle}>维护中</div>
                                        <div className={styles.headerVal}>{factoryData.f_maintain_num}</div>
                                    </div>
                                    <div className={styles.headerRightRight}>
                                        <div className={styles.headerRightRightItem}>
                                            <div className={styles.headerRightRightItemTitle}>故障抢修</div>
                                            <div className={styles.headerRightRightItemVal}>
                                                {maintainData.alarmNum}
                                            </div>
                                        </div>
                                        <div className={styles.headerRightRightItem}>
                                            <div className={styles.headerRightRightItemTitle}>油站原因</div>
                                            <div className={styles.headerRightRightItemVal}>
                                                {maintainData.stationNum}
                                            </div>
                                        </div>
                                        <div className={styles.headerRightRightItem}>
                                            <div className={styles.headerRightRightItemTitle}>设备升级</div>
                                            <div className={styles.headerRightRightItemVal}>
                                                {maintainData.upgradingNum}
                                            </div>
                                        </div>
                                        <div className={styles.headerRightRightItem}>
                                            <div className={styles.headerRightRightItemTitle}>天气原因</div>
                                            <div className={styles.headerRightRightItemVal}>
                                                {maintainData.frostNum}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <div className={styles.footer}>
                                <div className={styles.footerTitle}>运营率</div>
                                <div className={styles.footerValue}>
                                    {(
                                        operationRateDOD.reduce((preTotal, item) => preTotal + item.yyl, 0) /
                                        operationRateDOD.length
                                    ).toFixed(2) || '0.00'}
                                    %
                                </div>
                                <div className={styles.footerChartContainer}>
                                    <CompoundChart
                                        {...chartProps({
                                            ifCanClick: false,
                                            xKeyName: 'f_indate',
                                            yKeyName: 'yyl',
                                            data: operationRateDOD,
                                            geomList: [
                                                {
                                                    type: enum_geom_type.LINE,
                                                    size: getSize(3),
                                                    configList: [
                                                        {
                                                            typeKey: 'yyl',
                                                            typeName: '运营率',
                                                            color: '#6ABD08'
                                                        }
                                                    ],
                                                    otherOptions: {
                                                        tooltip: [
                                                            'yyl',
                                                            yyl => {
                                                                return {
                                                                    name: '运营率',
                                                                    value: yyl + '%'
                                                                };
                                                            }
                                                        ]
                                                    }
                                                }
                                            ]
                                        })}
                                    />
                                </div>
                            </div>
                        </div>
                    </div>
                </Content>
            </div>
        );
    }
}

export default errBoundary(Index);
